/* GENERATED by dev/tune_fixed.py (log1p, n = 3, r = 10) -- do not
   edit directly; retune or re-emit with
       python3 dev/tune_fixed.py log1p 3 --pin 10 --emit */

#include "flint.h"
#include "longlong.h"
#include "mpn_extras.h"
#include "fixed.h"
