/* atanh, n = 3, r = 10: 8 levels, widths [3, 3, 2, 2, 2, 1, 1, 1] */
static void
_fixed_log1p_series_3(nn_ptr res, nn_srcptr x)
{
    ulong z[3], V[3], T[3], P[3], Z[2];
    ulong v, w1, w0, h, l;
    slong i;

    (void) v; (void) w1; (void) w0; (void) h; (void) l;
    (void) i; (void) Z; (void) V; (void) T; (void) P;

    flint_mpn_sqrhigh(z, x, 3);

    v = UWORD(0x0f0f0f0f0f0f0f0f);

    /* V_6 = c + z V_7   (1 x 1 limbs) */
    v = n_mulhi(z[2], v);
    v = UWORD(0x1111111111111111) + v;

    /* V_5 = c + z V_6   (1 x 1 limbs) */
    v = n_mulhi(z[2], v);
    v = UWORD(0x13b13b13b13b13b1) + v;

    /* V_4 = c + z V_5   (2 x 1 limbs) */
    _fixed_mulhi_2x1(&h, &l, z[2], z[1], v);
    add_ssaaaa(w1, w0, UWORD(0x1745d1745d1745d1), UWORD(0x745d1745d1745d17), h, l);

    /* V_3 = c + z V_4   (2 x 2 limbs) */
    _fixed_mulhi_2x2_sloppy(&h, &l, z[2], z[1], w1, w0);
    add_ssaaaa(w1, w0, UWORD(0x1c71c71c71c71c71), UWORD(0xc71c71c71c71c71c), h, l);

    /* V_2 = c + z V_3   (2 x 2 limbs) */
    _fixed_mulhi_2x2_sloppy(&h, &l, z[2], z[1], w1, w0);
    add_ssaaaa(w1, w0, UWORD(0x2492492492492492), UWORD(0x4924924924924924), h, l);

    /* V_1 = c + z V_2   (3 x 2 limbs) */
    P[0] = UWORD(0);
    P[1] = w0; P[2] = w1;
    flint_mpn_mulhigh_n(T, z + 0, P, 3);
    P[0] = UWORD(0x3333333333333333);
    P[1] = UWORD(0x3333333333333333);
    P[2] = UWORD(0x3333333333333333);
    NN_ADD_3(V, P, T);

    /* V_0 = c + z V_1   (3 x 3 limbs) */
    P[0] = V[0];
    P[1] = V[1];
    P[2] = V[2];
    flint_mpn_mulhigh_n(T, z + 0, P, 3);
    P[0] = UWORD(0x5555555555555555);
    P[1] = UWORD(0x5555555555555555);
    P[2] = UWORD(0x5555555555555555);
    NN_ADD_3(V, P, T);

    /* atanh = x + x^3 V_0 */
    P[0] = V[0];
    P[1] = V[1];
    P[2] = V[2];
    flint_mpn_mulhigh_n(T, z, x, 3);
    flint_mpn_mulhigh_n(V, T, P, 3);
    NN_ADD_3(res, x, V);
}

void
fixed_log1p_opt_3(nn_ptr res, nn_srcptr x)
{
    const int r = 10;
    ulong d0, d1, d2;
    ulong p0, p1, p2;
    ulong a0, a1, a2;
    ulong e0, e1, e2;
    ulong v0, v1, v2;
    ulong bw, m, h, lt;
    ulong S[4], nd[6], t[3], y[3];
    slong i, nc;


    nn_srcptr tab;
    tab = _fixed_exp_logs_tab(3, r, &nc);

    d0 = x[0];
    d1 = x[1];
    d2 = x[2];
    p0 = 0;
    p1 = 0;
    p2 = 0;
    a0 = 0;
    a1 = 0;
    a2 = 0;

#define LP(ii) (tab + (ii) * nc + (nc - 3))

    /* window 0 */
    {
        nn_srcptr Lp;

        /* boundary step i = 1 */
        Lp = LP(1);
        v0 = MPN_RIGHT_SHIFT_LOW(p1, p0, 1);
        v1 = MPN_RIGHT_SHIFT_LOW(p2, p1, 1);
        v2 = MPN_RIGHT_SHIFT_LOW(UWORD(1), p2, 1);
        sub_ddddmmmmssss(bw, e2, e1, e0,
            UWORD(0), d2, d1, d0,
            UWORD(0), v2, v1, v0);
        m = ~bw;                /* accept iff no borrow */
        d0 = (d0 & bw) | (e0 & m);
        d1 = (d1 & bw) | (e1 & m);
        d2 = (d2 & bw) | (e2 & m);
        add_sssaaaaaa(p2, p1, p0,
            p2, p1, p0,
            (v2) & m, (v1) & m, (v0) & m);
        add_sssaaaaaa(a2, a1, a0,
            a2, a1, a0,
            Lp[2] & m, Lp[1] & m, Lp[0] & m);

        h = d2;

        for (i = 2; i <= 10; i++)
        {
            int b = (int) (i - 0);

            lt = MPN_RIGHT_SHIFT_LOW(UWORD(1), p2, b);
            if (h < lt)
                continue;    /* certain reject */

            Lp = LP(i);
            v0 = MPN_RIGHT_SHIFT_LOW(p1, p0, b);
            v1 = MPN_RIGHT_SHIFT_LOW(p2, p1, b);
            v2 = lt;
            sub_ddddmmmmssss(bw, e2, e1, e0,
                UWORD(0), d2, d1, d0,
                UWORD(0), v2, v1, v0);
            m = ~bw;                /* accept iff no borrow */
            d0 = (d0 & bw) | (e0 & m);
            d1 = (d1 & bw) | (e1 & m);
            d2 = (d2 & bw) | (e2 & m);
            add_sssaaaaaa(p2, p1, p0,
                p2, p1, p0,
                (v2) & m, (v1) & m, (v0) & m);
            add_sssaaaaaa(a2, a1, a0,
                a2, a1, a0,
                Lp[2] & m, Lp[1] & m, Lp[0] & m);
            h = d2;
        }
    }

    /* one extra step at i = r absorbs the truncation creep */
    {
        nn_srcptr Lp = LP((slong) r);
        const int b = 10;

        v0 = MPN_RIGHT_SHIFT_LOW(p1, p0, b);
        v1 = MPN_RIGHT_SHIFT_LOW(p2, p1, b);
        v2 = MPN_RIGHT_SHIFT_LOW(UWORD(1), p2, b);
        sub_ddddmmmmssss(bw, e2, e1, e0,
            UWORD(0), d2, d1, d0,
            UWORD(0), v2, v1, v0);
        m = ~bw;                /* accept iff no borrow */
        d0 = (d0 & bw) | (e0 & m);
        d1 = (d1 & bw) | (e1 & m);
        d2 = (d2 & bw) | (e2 & m);
        add_sssaaaaaa(p2, p1, p0,
            p2, p1, p0,
            (v2) & m, (v1) & m, (v0) & m);
        add_sssaaaaaa(a2, a1, a0,
            a2, a1, a0,
            Lp[2] & m, Lp[1] & m, Lp[0] & m);
    }

#undef LP

    /* t = D 2^(FLINT_BITS 3) / (X + P) */
    add_ssssaaaaaaaa(S[3], S[2], S[1], S[0],
        UWORD(1), x[2], x[1], x[0],
        UWORD(1), p2, p1, p0);
    nd[0] = 0;
    nd[1] = 0;
    nd[2] = 0;
    nd[3] = d0;
    nd[4] = d1;
    nd[5] = d2;
    flint_mpn_zero(t, 3);
    if (d2 != 0 || d1 != 0 || d0 != 0)
        mpn_tdiv_qr(t, nd, 0, nd, 6, S, 4);

    _fixed_log1p_series_3(y, t);

    add_sssaaaaaa(res[2], res[1], res[0],
        a2, a1, a0,
        (y[2] << 1) | (y[1] >> (FLINT_BITS - 1)), (y[1] << 1) | (y[0] >> (FLINT_BITS - 1)), y[0] << 1);
}


